def field_name(column: str) -> str:
    """Map an ADMET column name to a valid Python attribute name.

    admet_ai column names like ``NR-AR-LBD`` and ``SR-p53`` carry hyphens
    that are not valid Python identifiers, so they cannot be used as
    dataclass field names directly. Replace ``-`` with ``_`` and prefix
    with ``admet_`` to get the canonical attribute name we expose on
    ``Candidate`` and emit in CSV / Parquet outputs. Case is preserved so
    a reader can map back to the admet_ai column unambiguously.
    """
    return "admet_" + column.replace("-", "_")


